INSERT INTO public.items (slug,name,category,subcategory,source,rarity,weight_lb,cost_gp,description,properties) VALUES ('crystal','Crystal','adventuring_gear',NULL,'SRD','common',1,10,'An arcane focus is a special item--an orb, a crystal, a rod, a specially constructed staff, a wand-like length of wood, or some similar item--designed to channel the power of arcane spells. A sorcerer, warlock, or wizard can use such an item as a spellcasting focus.','{}') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,category=EXCLUDED.category,subcategory=EXCLUDED.subcategory,weight_lb=EXCLUDED.weight_lb,cost_gp=EXCLUDED.cost_gp,description=EXCLUDED.description,properties=EXCLUDED.properties,updated_at=now();
