INSERT INTO public.items (slug,name,category,subcategory,source,rarity,weight_lb,cost_gp,description,properties) VALUES ('dice-set','Dice Set','tool',NULL,'SRD','common',0,0.1,'This item encompasses a wide range of game pieces, including dice and decks of cards (for games such as Three-Dragon Ante). A few common examples appear on the Tools table, but other kinds of gaming sets exist. If you are proficient with a gaming set, you can add your proficiency bonus to ability checks you make to play a game with that set. Each type of gaming set requires a separate proficiency.','{}') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,category=EXCLUDED.category,subcategory=EXCLUDED.subcategory,weight_lb=EXCLUDED.weight_lb,cost_gp=EXCLUDED.cost_gp,description=EXCLUDED.description,properties=EXCLUDED.properties,updated_at=now();
