INSERT INTO public.items (slug,name,category,subcategory,source,rarity,weight_lb,cost_gp,description,properties) VALUES ('magnifying-glass','Magnifying glass','adventuring_gear',NULL,'SRD','common',0,100,'This lens allows a closer look at small objects. It is also useful as a substitute for flint and steel when starting fires. Lighting a fire with a magnifying glass requires light as bright as sunlight to focus, tinder to ignite, and about 5 minutes for the fire to ignite. A magnifying glass grants advantage on any ability check made to appraise or inspect an item that is small or highly detailed.','{}') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,category=EXCLUDED.category,subcategory=EXCLUDED.subcategory,weight_lb=EXCLUDED.weight_lb,cost_gp=EXCLUDED.cost_gp,description=EXCLUDED.description,properties=EXCLUDED.properties,updated_at=now();
INSERT INTO public.items (slug,name,category,subcategory,source,rarity,weight_lb,cost_gp,description,properties) VALUES ('manacles','Manacles','adventuring_gear',NULL,'SRD','common',6,2,'These metal restraints can bind a Small or Medium creature. Escaping the manacles requires a successful DC 20 Dexterity check. Breaking them requires a successful DC 20 Strength check. Each set of manacles comes with one key. Without the key, a creature proficient with thieves'' tools can pick the manacles'' lock with a successful DC 15 Dexterity check. Manacles have 15 hit points.','{}') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,category=EXCLUDED.category,subcategory=EXCLUDED.subcategory,weight_lb=EXCLUDED.weight_lb,cost_gp=EXCLUDED.cost_gp,description=EXCLUDED.description,properties=EXCLUDED.properties,updated_at=now();
