INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('amulet-of-health','Amulet of Health','magic_item','SRD','rare','Wondrous item, rare (requires attunement) Your Constitution score is 19 while you wear this amulet. It has no effect on you if your Constitution is already 19 or higher','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('amulet-of-proof-against-detection-and-location','Amulet of Proof against Detection and Location','magic_item','SRD','uncommon','Wondrous item, uncommon (requires attunement) While wearing this amulet, you are hidden from divination magic. You can''t be targeted by such magic or perceived through magical scrying sensors.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('amulet-of-the-planes','Amulet of the Planes','magic_item','SRD','very_rare','Wondrous item, very rare (requires attunement) While wearing this amulet, you can use an action to name a location that you are familiar with on another plane of existence. Then make a DC 15 Intelligence check. On a successful check, you cast the plane shift spell. On a failure, you and each creature and object within 15 feet of you travel to a random destination. Roll a d100. On a 1-60, you travel to a random location on the plane you named. On a 61-100, you travel to a randomly determined plane of existence.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('animated-shield','Animated Shield','magic_item','SRD','very_rare','Armor (shield), very rare (requires attunement) While holding this shield, you can speak its command word as a bonus action to cause it to animate. The shield leaps into the air and hovers in your space to protect you as if you were wielding it, leaving your hands free. The shield remains animated for 1 minute, until you use a bonus action to end this effect, or until you are incapacitated or die, at which point the shield falls to the ground or into your hand if you have one free.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('apparatus-of-the-crab','Apparatus of the Crab','magic_item','SRD','legendary','Wondrous item, legendary This item first appears to be a Large sealed iron barrel weighing 500 pounds. The barrel has a hidden catch, which can be found with a successful DC 20 Intelligence (Investigation) check. Releasing the catch unlocks a hatch at one end of the barrel, allowing two Medium or smaller creatures to crawl inside. Ten levers are set in a row at the far end, each in a neutral position, able to move either up or down. When certain levers are used, the apparatus transforms to resemble a giant lobster. The apparatus of the Crab is a Large object with the following statistics:','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('armor','Armor, +1, +2, or +3','magic_item','SRD','varies','Armor (light, medium, or heavy), rare (+1), very rare (+2), or legendary (+3) You have a bonus to AC while wearing this armor. The bonus is determined by its rarity.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('armor-1','Armor, +1','magic_item','SRD','rare','Armor (light, medium, or heavy), rare You have a +1 bonus to AC while wearing this armor.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('armor-2','Armor, +2','magic_item','SRD','very_rare','Armor (light, medium, or heavy), very rare You have a +2 bonus to AC while wearing this armor.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('armor-3','Armor, +3','magic_item','SRD','legendary','Armor (light, medium, or heavy), legendary You have a +3 bonus to AC while wearing this armor.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('armor-of-invulnerability','Armor of Invulnerability','magic_item','SRD','legendary','Armor (plate), legendary (requires attunement) You have resistance to nonmagical damage while you wear this armor. Additionally, you can use an action to make yourself immune to nonmagical damage for 10 minutes or until you are no longer wearing the armor. Once this special action is used, it can''t be used again until the next dawn.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('armor-of-resistance','Armor of Resistance','magic_item','SRD','rare','Armor (light, medium, or heavy), rare (requires attunement) You have resistance to one type of damage while you wear this armor. The GM chooses the type or determines it randomly from the options below. | d10 | Damage Type |','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('armor-of-vulnerability','Armor of Vulnerability','magic_item','SRD','rare','Armor (plate), rare (requires attunement) While wearing this armor, you have resistance to  one of the following damage types: bludgeoning, piercing, or slashing. The GM chooses the type or determines it randomly. ***Curse.*** This armor is cursed, a fact that is revealed only when an identify spell is cast on the armor or you attune to it. Attuning to the armor curses you until you are targeted by the remove curse spell or similar magic; removing the armor fails to end the curse. While cursed, you have vulnerability to two of the three damage types associated with the armor (not the one to which it grants resistance).','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('arrow-catching-shield','Arrow-Catching Shield','magic_item','SRD','rare','Armor (shield), rare (requires attunement) You gain a +2 bonus to AC against ranged attacks while you wield this shield. This bonus is in addition to the shield''s normal bonus to AC. In addition, whenever an attacker makes a ranged attack against a target within 5 feet of you, you can use your reaction to become the target of the attack instead.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('arrow-of-slaying','Arrow of Slaying','magic_item','SRD','very_rare','Weapon (arrow), very rare An arrow of slaying is a magic weapon meant to slay a particular kind of creature. Some are more focused than others; for example, there are both arrows of dragon slaying and arrows of blue dragon slaying. If a creature belonging to the type, race, or group associated with an arrow of slaying takes damage from the arrow, the creature must make a DC 17 Constitution saving throw, taking an extra 6d10 piercing damage on a failed save, or half as much extra damage on a successful one. Once an arrow of slaying deals its extra damage to a creature, it becomes a nonmagical arrow.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('bag-of-beans','Bag of Beans','magic_item','SRD','rare','Wondrous item, rare Inside this heavy cloth bag are 3d4 dry beans. The bag weighs 1/2 pound plus 1/4 pound for each bean it contains. If you dump the bag''s contents out on the ground,  they explode in a 10-foot radius, extending from the beans. Each creature in the area, including you, must  make a DC 15 Dexterity saving throw, taking 5d4 fire  damage on a failed save, or half as much damage on  a successful one. The fire ignites flammable objects  in the area that aren''t being worn or carried.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('bag-of-devouring','Bag of Devouring','magic_item','SRD','very_rare','Wondrous item, very rare This bag superficially resembles a bag of holding but is a feeding orifice for a gigantic extradimensional creature. Turning the bag inside out closes the orifice. The extradimensional creature attached to the bag can sense whatever is placed inside the bag. Animal or vegetable matter placed wholly in the bag is devoured and lost forever. When part of a living creature is placed in the bag, as happens when someone reaches inside it, there is a 50 percent chance that the creature is pulled inside the bag. A creature inside the bag can use its action to try to escape with a successful DC 15 Strength check. Another creature can use its action to reach into the bag to pull a creature out, doing so with a successful DC 20 Strength check (provided it isn''t pulled inside the bag first). Any creature that starts its turn inside the bag is devoured, its body destroyed.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('bag-of-holding','Bag of Holding','magic_item','SRD','uncommon','Wondrous item, uncommon This bag has an interior space considerably larger than its outside dimensions, roughly 2 feet in diameter at the mouth and 4 feet deep. The bag can hold up to 500 pounds, not exceeding a volume of 64 cubic feet. The bag weighs 15 pounds, regardless of its contents. Retrieving an item from the bag requires an action. If the bag is overloaded, pierced, or torn, it ruptures and is destroyed, and its contents are scattered in the Astral Plane. If the bag is turned inside out, its contents spill forth, unharmed, but the bag must be put right before it can be used again. Breathing creatures inside the bag can survive up to a number of minutes equal to 10 divided by the number of creatures (minimum 1 minute), after which time they begin to suffocate.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('bag-of-tricks','Bag of Tricks','magic_item','SRD','uncommon','Wondrous item, uncommon This ordinary bag, made from gray, rust, or tan cloth, appears empty. Reaching inside the bag, however, reveals the presence of a small, fuzzy object. The bag weighs 1/2 pound. You can use an action to pull the fuzzy object from the bag and throw it up to 20 feet. When the object lands, it transforms into a creature you determine by rolling a d8 and consulting the table that corresponds to the bag''s color. The creature vanishes at the next dawn or when it is reduced to 0 hit points.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('bag-of-tricks-gray','Gray Bag of Tricks','magic_item','SRD','uncommon','Wondrous item, uncommon This ordinary bag, made from gray cloth, appears empty. Reaching inside the bag, however, reveals the presence of a small, fuzzy object. The bag weighs 1/2 pound. You can use an action to pull the fuzzy object from the bag and throw it up to 20 feet. When the object lands, it transforms into a creature you determine by rolling a d8 and consulting the table that corresponds to the bag''s color. The creature vanishes at the next dawn or when it is reduced to 0 Hit Points.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('bag-of-tricks-rust','Rust Bag of Tricks','magic_item','SRD','uncommon','Wondrous item, uncommon This ordinary bag, made from rust cloth, appears empty. Reaching inside the bag, however, reveals the presence of a small, fuzzy object. The bag weighs 1/2 pound. You can use an action to pull the fuzzy object from the bag and throw it up to 20 feet. When the object lands, it transforms into a creature you determine by rolling a d8 and consulting the table that corresponds to the bag''s color. The creature vanishes at the next dawn or when it is reduced to 0 Hit Points.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('bag-of-tricks-tan','Tan Bag of Tricks','magic_item','SRD','uncommon','Wondrous item, uncommon This ordinary bag, made from tan cloth, appears empty. Reaching inside the bag, however, reveals the presence of a small, fuzzy object. The bag weighs 1/2 pound. You can use an action to pull the fuzzy object from the bag and throw it up to 20 feet. When the object lands, it transforms into a creature you determine by rolling a d8 and consulting the table that corresponds to the bag''s color. The creature vanishes at the next dawn or when it is reduced to 0 Hit Points.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('bead-of-force','Bead of Force','magic_item','SRD','rare','Wondrous item, rare This small black Sphere measures 3/4 of an inch in diameter and weighs an ounce. Typically, 1d4 + 4 beads of force are found together. You can use an action to throw the bead up to 60 feet. The bead explodes on impact and is destroyed. Each creature within a 10-foot radius of where the bead landed must succeed on a DC 15 Dexterity saving throw or take 5d4 force damage. A Sphere of transparent force then encloses the area for 1 minute. Any creature that failed the save and is completely within the area is trapped inside this Sphere. Creatures that succeeded on the save, or are partially within the area, are pushed away from the center of the Sphere until they are no longer inside it. Only breathable air can pass through the sphere''s wall. No Attack or other Effect can.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('belt-of-dwarvenkind','Belt of Dwarvenkind','magic_item','SRD','rare','Wondrous Items, rare (requires attunement) While wearing this belt, you gain the following benefits: Your Constitution score increases by 2, to a maximum of 20.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('belt-of-giant-strength','Belt of Giant Strength','magic_item','SRD','varies','Wondrous item, rarity varies (requires attunement) While wearing this belt, your Strength score changes to a score granted by the belt. If your Strength is already equal to or greater than the belt''s score, the item has no Effect on you. Six varieties of this belt exist, corresponding with and having rarity according to The Six kinds of true Giants. The belt of Stone Giant Strength and the belt of Frost Giant Strength look different, but they have the same Effect.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('belt-of-giant-strength-cloud','Belt of Cloud Giant Strength','magic_item','SRD','legendary','Wondrous item, legendary (requires attunement) While wearing this belt, your Strength score changes to 27. If your Strength is already equal to or greater than the belt''s score, the item has no Effect on you.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('belt-of-giant-strength-fire','Belt of Fire Giant Strength','magic_item','SRD','very_rare','Wondrous item, very rare (requires attunement) While wearing this belt, your Strength score changes to 25. If your Strength is already equal to or greater than the belt''s score, the item has no Effect on you.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('belt-of-giant-strength-frost','Belt of Frost Giant Strength','magic_item','SRD','very_rare','Wondrous item, very rare (requires attunement) While wearing this belt, your Strength score changes to 23. If your Strength is already equal to or greater than the belt''s score, the item has no Effect on you.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('belt-of-giant-strength-hill','Belt of Hill Giant Strength','magic_item','SRD','rare','Wondrous item, rare (requires attunement) While wearing this belt, your Strength score changes to a 21. If your Strength is already equal to or greater than the belt''s score, the item has no Effect on you.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('belt-of-giant-strength-stone','Belt of Stone Giant Strength','magic_item','SRD','very_rare','Wondrous item, very rare (requires attunement) While wearing this belt, your Strength score changes to a 23. If your Strength is already equal to or greater than the belt''s score, the item has no Effect on you.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('belt-of-giant-strength-storm','Belt of Storm Giant Strength','magic_item','SRD','legendary','Wondrous item, legendary (requires attunement) While wearing this belt, your Strength score changes to 29. If your Strength is already equal to or greater than the belt''s score, the item has no Effect on you.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('berserker-axe','Berserker Axe','magic_item','SRD','rare','Weapon (any axe), rare (requires attunement) You gain a +1 bonus to Attack and Damage Rolls made with this Magic Weapon. In addition, while you are attuned to this weapon, your Hit Points maximum increases by 1 for each level you have attained. ***Curse.*** This axe is Cursed, and becoming attuned to it extends the curse to you. As long as you remain Cursed, you are unwilling to part with the axe, keeping it within reach at all times. You also have disadvantage on Attack rolls with Weapons other than this one, unless no foe is within 60 feet of you that you can see or hear.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('boots-of-elvenkind','Boots of Elvenkind','magic_item','SRD','uncommon','Wondrous item, uncommon While you wear these boots, your steps make no sound, regardless of the surface you are moving across. You also have advantage on Dexterity (Stealth) checks that rely on moving silently.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('boots-of-levitation','Boots of Levitation','magic_item','SRD','rare','Wondrous item, rare (requires attunement) While you wear these boots, you can use an action to cast the levitate spell on yourself at will.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('boots-of-speed','Boots of Speed','magic_item','SRD','rare','Wondrous item, rare (requires attunement) While you wear these boots, you can use a bonus action and click the boots'' heels together. If you do, the boots double your walking speed, and any creature that makes an opportunity attack against you has disadvantage on the attack roll. If you click your heels together again, you end the effect. When the boots'' property has been used for a total of 10 minutes, the magic ceases to function until you finish a long rest.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('boots-of-striding-and-springing','Boots of Striding and Springing','magic_item','SRD','uncommon','Wondrous item, uncommon (requires attunement) While you wear these boots, your walking speed becomes 30 feet, unless your walking speed is higher, and your speed isn''t reduced if you are encumbered or wearing heavy armor. In addition, you can jump three times the normal distance, though you can''t jump farther than your remaining movement would allow.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('boots-of-the-winterlands','Boots of the Winterlands','magic_item','SRD','uncommon','Wondrous item, uncommon (requires attunement) These furred boots are snug and feel quite warm. While you wear them, you gain the following benefits: * You have resistance to cold damage.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('bowl-of-commanding-water-elementals','Bowl of Commanding Water Elementals','magic_item','SRD','rare','Wondrous item, rare While this bowl is filled with water, you can use an action to speak the bowl''s command word and summon a water elemental, as if you had cast the conjure elemental spell. The bowl can''t be used this way again until the next dawn. The bowl is about 1 foot in diameter and half as deep. It weighs 3 pounds and holds about 3 gallons.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('bracers-of-archery','Bracers of Archery','magic_item','SRD','uncommon','Wondrous item, uncommon (requires attunement) While wearing these bracers, you have proficiency with the longbow and shortbow, and you gain a +2 bonus to damage rolls on ranged attacks made with such weapons.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('bracers-of-defense','Bracers of Defense','magic_item','SRD','rare','Wondous item, rare (requires attunement) While wearing these bracers, you gain a +2 bonus to AC if you are wearing no armor and using no shield.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('brazier-of-commanding-fire-elementals','Brazier of Commanding Fire Elementals','magic_item','SRD','rare','Wondrous item, rare While a fire burns in this brass brazier, you can use an action to speak the brazier''s command word and summon a fire elemental, as if you had cast the conjure elemental spell. The brazier can''t be used this way again until the next dawn. The brazier weighs 5 pounds.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('brooch-of-shielding','Brooch of Shielding','magic_item','SRD','uncommon','Wondrous item, uncommon (requires attunement) While wearing this brooch, you have resistance to force damage, and you have immunity to damage from the magic missile spell.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('broom-of-flying','Broom of Flying','magic_item','SRD','uncommon','Wondrous item, uncommon This wooden broom, which weighs 3 pounds, functions like a mundane broom until you stand astride it and speak its command word. It then hovers beneath you and can be ridden in the air. It has a flying speed of 50 feet. It can carry up to 400 pounds, but its flying speed becomes 30 feet while carrying over 200 pounds. The broom stops hovering when you land. You can send the broom to travel alone to a destination within 1 mile of you if you speak the command word, name the location, and are familiar with that place. The broom comes back to you when you speak another command word, provided that the broom is still within 1 mile of you.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('candle-of-invocation','Candle of Invocation','magic_item','SRD','very_rare','Wondrous item, very rare (requires attunement) This slender taper is dedicated to a deity and shares that deity''s alignment. The candle''s alignment can be detected with the detect evil and good spell. The GM chooses the god and associated alignment or determines the alignment randomly. | d20 | Alignment |','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('cape-of-the-mountebank','Cape of the Mountebank','magic_item','SRD','rare','Wondrous item, rare This cape smells faintly of brimstone. While wearing it, you can use it to cast the dimension door spell as an action. This property of the cape can''t be used again until the next dawn. When you disappear, you leave behind a cloud of smoke, and you appear in a similar cloud of smoke at your destination. The smoke lightly obscures the space you left and the space you appear in, and it dissipates at the end of your next turn. A light or stronger wind disperses the smoke.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('carpet-of-flying','Carpet of Flying','magic_item','SRD','very_rare','Wondrous item, very rare You can speak the carpet''s command word as an  action to make the carpet hover and fly. It moves according to your spoken directions, provided that you are within 30 feet of it. Four sizes of carpet of flying exist. The GM chooses the size of a given carpet or determines it randomly.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('carpet-of-flying-3x5','Carpet of Flying (3 ft. × 5 ft.)','magic_item','SRD','very_rare','Wondrous item, very rare You can speak the carpet''s command word as an  action to make the carpet hover and fly. It moves according to your spoken directions, provided that you are within 30 feet of it. This carpet is 3 feet by 5 feet and has a flying speed of 80 feet. It can carry up to 400 pounds, but its flying speed becomes 40 feet while carrying over 200 pounds.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('carpet-of-flying-4x6','Carpet of Flying (4 ft. × 6 ft.)','magic_item','SRD','very_rare','Wondrous item, very rare You can speak the carpet''s command word as an  action to make the carpet hover and fly. It moves according to your spoken directions, provided that you are within 30 feet of it. This carpet is 4 feet by 6 feet and has a flying speed of 60 feet. It can carry up to 800 pounds, but its flying speed becomes 30 feet while carrying over 400 pounds.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('carpet-of-flying-5x7','Carpet of Flying (5 ft. × 7 ft.)','magic_item','SRD','very_rare','Wondrous item, very rare You can speak the carpet''s command word as an  action to make the carpet hover and fly. It moves according to your spoken directions, provided that you are within 30 feet of it. This carpet is 5 feet by 7 feet and has a flying speed of 40 feet. It can carry up to 1200 pounds, but its flying speed becomes 20 feet while carrying over 600 pounds.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('carpet-of-flying-6x9','Carpet of Flying (6 ft. × 9 ft.)','magic_item','SRD','very_rare','Wondrous item, very rare You can speak the carpet''s command word as an  action to make the carpet hover and fly. It moves according to your spoken directions, provided that you are within 30 feet of it. This carpet is 6 feet by 9 feet and has a flying speed of 30 feet. It can carry up to 1600 pounds, but its flying speed becomes 15 feet while carrying over 800 pounds.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('censer-of-controlling-air-elementals','Censer of Controlling Air Elementals','magic_item','SRD','rare','Wondrous item, rare While incense is burning in this censer, you can use an action to speak the censer''s command word and summon an air elemental, as if you had cast the conjure elemental spell. The censer can''t be used this way again until the next dawn. This 6-inch-wide, 1-foot-high vessel resembles a chalice with a decorated lid. It weighs 1 pound.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('chime-of-opening','Chime of Opening','magic_item','SRD','rare','Wondrous item, rare This hollow metal tube measures about 1 foot long and weighs 1 pound. You can strike it as an action, pointing it at an object within 120 feet of you that can be opened, such as a door, lid, or lock. The chime issues a clear tone, and one lock or latch on the object opens unless the sound can''t reach the object. If no locks or latches remain, the object itself opens. The chime can be used ten times. After the tenth time, it cracks and becomes useless.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('circlet-of-blasting','Circlet of Blasting','magic_item','SRD','uncommon','Wondrous item, uncommon While wearing this circlet, you can use an action to cast the scorching ray spell with it. When you make the spell''s attacks, you do so with an attack bonus of +5. The circlet can''t be used this way again until the next dawn.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('cloak-of-arachnida','Cloak of Arachnida','magic_item','SRD','very_rare','Wondrous item, very rare (requires attunement) This fine garment is made of black silk interwoven with faint silvery threads. While wearing it, you gain the following benefits: * You have resistance to poison damage.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('cloak-of-displacement','Cloak of Displacement','magic_item','SRD','rare','Wondrous item, rare (requires attunement) While you wear this cloak, it projects an illusion that makes you appear to be standing in a place near your actual location, causing any creature to have disadvantage on attack rolls against you. If you take damage, the property ceases to function until the start of your next turn. This property is suppressed while you are incapacitated, restrained, or otherwise unable to move.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('cloak-of-elvenkind','Cloak of Elvenkind','magic_item','SRD','uncommon','Wondrous item, uncommon (requires attunement) While you wear this cloak with its hood up, Wisdom (Perception) checks made to see you have disadvantage, and you have advantage on Dexterity (Stealth) checks made to hide, as the cloak''s color shifts to camouflage you. Pulling the hood up or down requires an action.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('cloak-of-protection','Cloak of Protection','magic_item','SRD','uncommon','Wondrous item, uncommon (requires attunement) You gain a +1 bonus to AC and saving throws while you wear this cloak.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('cloak-of-the-bat','Cloak of the Bat','magic_item','SRD','rare','Wondrous item, rare (requires attunement) While wearing this cloak, you have advantage on Dexterity (Stealth) checks. In an area of dim light or darkness, you can grip the edges of the cloak with both hands and use it to fly at a speed of 40 feet. If you ever fail to grip the cloak''s edges while flying in this way, or if you are no longer in dim light or darkness, you lose this flying speed. While wearing the cloak in an area of dim light or darkness, you can use your action to cast polymorph on yourself, transforming into a bat. While you are in the form of the bat, you retain your Intelligence, Wisdom, and Charisma scores. The cloak can''t be used this way again until the next dawn.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('cloak-of-the-manta-ray','Cloak of the Manta Ray','magic_item','SRD','uncommon','Wondrous item, uncommon While wearing this cloak with its hood up, you can breathe underwater, and you have a swimming speed of 60 feet. Pulling the hood up or down requires an action.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('crystal-ball','Crystal Ball','magic_item','SRD','very_rare','Wondrous item, very rare or legendary (requires attunement) The typical crystal ball, a very rare item, is about 6 inches in diameter. While touching it, you can cast the scrying spell (save DC 17) with it. The following crystal ball variants are legendary items and have additional properties.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('crystal-ball-of-mind-reading','Crystal Ball of Mind Reading','magic_item','SRD','legendary','Wondrous item, legendary (requires attunement) The crystal ball is about 6 inches in diameter. While touching it, you can cast the scrying spell (save DC 17) with it. ***Crystal Ball of Mind Reading.*** You can use an action to cast the detect thoughts spell (save DC 17) while you are scrying with the crystal ball, targeting creatures you can see within 30 feet of the spell''s sensor. You don''t need to concentrate on this detect thoughts to maintain it during its duration, but it ends if scrying ends.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('crystal-ball-of-telepathy','Crystal Ball of Telepathy','magic_item','SRD','legendary','Wondrous item, legendary (requires attunement) The crystal ball is about 6 inches in diameter. While touching it, you can cast the scrying spell (save DC 17) with it. ***Crystal Ball of Telepathy.*** While scrying with the crystal ball, you can communicate telepathically with creatures you can see within 30 feet of the spell''s sensor. You can also use an action to cast the suggestion spell (save DC 17) through the sensor on one of those creatures. You don''t need to concentrate on this suggestion to maintain it during its duration, but it ends if scrying ends. Once used, the suggestion power of the crystal ball can''t be used again until the next dawn.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('crystal-ball-of-true-seeing','Crystal Ball of True Seeing','magic_item','SRD','legendary','Wondrous item, legendary (requires attunement) The crystal ball is about 6 inches in diameter. While touching it, you can cast the scrying spell (save DC 17) with it. ***Crystal Ball of True Seeing.*** While scrying with the crystal ball, you have truesight with a radius of 120 feet centered on the spell''s sensor.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('cube-of-force','Cube of Force','magic_item','SRD','rare','Wondrous item, rare (requires attunement) This cube is about an inch across. Each face has a distinct marking on it that can be pressed. The cube starts with 36 charges, and it regains 1d20 expended charges daily at dawn. You can use an action to press one of the cube''s faces, expending a number of charges based on the chosen face, as shown in the Cube of Force Faces table. Each face has a different effect. If the cube has insufficient charges remaining, nothing happens. Otherwise, a barrier of invisible force springs into existence, forming a cube 15 feet on a side. The barrier is centered on you, moves with you, and lasts for 1 minute, until you use an action to press the cube''s sixth face, or the cube runs out of charges. You can change the barrier''s effect by pressing a different face of the cube and expending the requisite number of charges, resetting the duration.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('cubic-gate','Cubic Gate','magic_item','SRD','legendary','Wondrous item, legendary This cube is 3 inches across and radiates palpable magical energy. The six sides of the cube are each keyed to a different plane of existence, one of which is the Material Plane. The other sides are linked to planes determined by the GM. You can use an action to press one side of the cube to cast the gate spell with it, opening a portal to the plane keyed to that side. Alternatively, if you use an action to press one side twice, you can cast the plane shift spell (save DC 17) with the cube and transport the targets to the plane keyed to that side.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('dagger-of-venom','Dagger of Venom','magic_item','SRD','rare','Weapon (dagger), rare You gain a +1 bonus to attack and damage rolls made with this magic weapon. You can use an action to cause thick, black poison to coat the blade. The poison remains for 1 minute or until an attack using this weapon hits a creature. That creature must succeed on a DC 15 Constitution saving throw or take 2d10 poison damage and become poisoned for 1 minute. The dagger can''t be used this way again until the next dawn.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('dancing-sword','Dancing Sword','magic_item','SRD','very_rare','Weapon (any sword), very rare (requires attunement) You can use a bonus action to toss this magic sword into the air and speak the command word. When you do so, the sword begins to hover, flies up to 30 feet, and attacks one creature of your choice within 5 feet of it. The sword uses your attack roll and ability score modifier to damage rolls. While the sword hovers, you can use a bonus action to cause it to fly up to 30 feet to another spot within 30 feet of you. As part of the same bonus action, you can cause the sword to attack one creature within 5 feet of it.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('decanter-of-endless-water','Decanter of Endless Water','magic_item','SRD','uncommon','Wondrous item, uncommon This stoppered flask sloshes when shaken, as if it contains water. The decanter weighs 2 pounds. You can use an action to remove the stopper and speak one of three command words, whereupon an amount of fresh water or salt water (your choice) pours out of the flask. The water stops pouring out at the start of your next turn. Choose from the following options:','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('deck-of-illusions','Deck of Illusions','magic_item','SRD','uncommon','Wondrous item, uncommon This box contains a set of parchment cards. A full deck has 34 cards. A deck found as treasure is usually missing 1d20 - 1 cards. The magic of the deck functions only if cards are drawn at random (you can use an altered deck of playing cards to simulate the deck). You can use an action to draw a card at random from the deck and throw it to the ground at a point within 30 feet of you.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('deck-of-many-things','Deck of Many Things','magic_item','SRD','legendary','Wondrous item, legendary Usually found in a box or pouch, this deck contains a number of cards made of ivory or vellum. Most (75 percent) of these decks have only thirteen cards, but the rest have twenty-two. Before you draw a card, you must declare how many cards you intend to draw and then draw them randomly (you can use an altered deck of playing cards to simulate the deck). Any cards drawn in excess of this number have no effect. Otherwise, as soon as you draw a card from the deck, its magic takes effect. You must draw each card no more than 1 hour after the previous draw. If you fail to draw the chosen number, the remaining number of cards fly from the deck on their own and take effect all at once.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('defender','Defender','magic_item','SRD','legendary','Weapon (any sword), legendary (requires attunement) You gain a +3 bonus to attack and damage rolls made with this magic weapon. The first time you attack with the sword on each of your turns, you can transfer some or all of the sword''s bonus to your Armor Class, instead of using the bonus on any attacks that turn. For example, you could reduce the bonus to your attack and damage rolls to +1 and gain a +2 bonus to AC. The adjusted bonuses remain in effect until the start of your next turn, although you must hold the sword to gain a bonus to AC from it.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('demon-armor','Demon Armor','magic_item','SRD','very_rare','Armor (plate), very rare (requires attunement) While wearing this armor, you gain a +1 bonus to AC, and you can understand and speak Abyssal. In addition, the armor''s clawed gauntlets turn unarmed strikes with your hands into magic weapons that deal slashing damage, with a +1 bonus to attack rolls and damage rolls and a damage die of 1d8. ***Curse.*** Once you don this cursed armor, you can''t doff it unless you are targeted by the remove curse spell or similar magic. While wearing the armor, you have disadvantage on attack rolls against demons and on saving throws against their spells and special abilities.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('dimensional-shackles','Dimensional Shackles','magic_item','SRD','rare','Wondrous item, rare You can use an action to place these shackles on an incapacitated creature. The shackles adjust to fit a creature of Small to Large size. In addition to serving as mundane manacles, the shackles prevent a creature bound by them from using any method of extradimensional movement, including teleportation or travel to a different plane of existence. They don''t prevent the creature from passing through an interdimensional portal. You and any creature you designate when you use the shackles can use an action to remove them. Once every 30 days, the bound creature can make a DC 30 Strength (Athletics) check. On a success, the creature breaks free and destroys the shackles.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('dragon-scale-mail','Dragon Scale Mail','magic_item','SRD','very_rare','Armor (scale mail), very rare (requires attunement) Dragon scale mail is made of the scales of one kind of dragon. Sometimes dragons collect their cast-off scales and gift them to humanoids. Other times, hunters carefully skin and preserve the hide of a dead dragon. In either case, dragon scale mail is highly valued. While wearing this armor, you gain a +1 bonus to AC, you have advantage on saving throws against the Frightful Presence and breath weapons of dragons, and you have resistance to one damage type that is determined by the kind of dragon that provided the scales (see the table).','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('dragon-scale-mail-black','Black Dragon Scale Mail','magic_item','SRD','very_rare','Armor (scale mail), very rare (requires attunement) Dragon scale mail is made of the scales of a black dragon. Sometimes dragons collect their cast-off scales and gift them to humanoids. Other times, hunters carefully skin and preserve the hide of a dead dragon. In either case, dragon scale mail is highly valued. While wearing this armor, you gain a +1 bonus to AC, you have advantage on saving throws against the Frightful Presence and breath weapons of dragons, and you have resistance to acid damage.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('dragon-scale-mail-blue','Blue Dragon Scale Mail','magic_item','SRD','very_rare','Armor (scale mail), very rare (requires attunement) Dragon scale mail is made of the scales of a blue dragon. Sometimes dragons collect their cast-off scales and gift them to humanoids. Other times, hunters carefully skin and preserve the hide of a dead dragon. In either case, dragon scale mail is highly valued. While wearing this armor, you gain a +1 bonus to AC, you have advantage on saving throws against the Frightful Presence and breath weapons of dragons, and you have resistance to lightning damage.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
