INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('potion-of-heroism','Potion of Heroism','magic_item','SRD','rare','Potion, rare For 1 hour after drinking it, you gain 10 temporary hit points that last for 1 hour. For the same duration, you are under the effect of the bless spell (no concentration required). This blue potion bubbles and steams as if boiling.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('potion-of-invisibility','Potion of Invisibility','magic_item','SRD','very_rare','Potion, very rare This potion''s container looks empty but feels as though it holds liquid. When you drink it, you become invisible for 1 hour. Anything you wear or carry is invisible with you. The effect ends early if you attack or cast a spell.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('potion-of-mind-reading','Potion of Mind Reading','magic_item','SRD','rare','Potion, rare When you drink this potion, you gain the effect of the detect thoughts spell (save DC 13). The potion''s dense, purple liquid has an ovoid cloud of pink floating in it.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('potion-of-poison','Potion of Poison','magic_item','SRD','uncommon','Potion, uncommon This concoction looks, smells, and tastes like a potion of healing or other beneficial potion. However, it is actually poison masked by illusion magic. An identify spell reveals its true nature. If you drink it, you take 3d6 poison damage, and you must succeed on a DC 13 Constitution saving throw or be poisoned. At the start of each of your turns while you are poisoned in this way, you take 3d6 poison damage. At the end of each of your turns, you can repeat the saving throw. On a successful save, the poison damage you take on your subsequent turns decreases by 1d6. The poison ends when the damage decreases to 0.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('potion-of-resistance','Potion of Resistance','magic_item','SRD','uncommon','Potion, uncommon When you drink this potion, you gain resistance to one type of damage for 1 hour. The GM chooses the type or determines it randomly from the options below. | d10 | Damage Type |','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
