INSERT INTO public.items (slug,name,category,source,rarity,description,properties,requires_attunement,is_magic) VALUES ('spell-scroll-6th','Spell Scroll (6th)','magic_item','SRD','very_rare','Scroll, very rare A spell scroll bears the words of a single spell, written in a mystical cipher. If the spell is on your class''s spell list, you can read the scroll and cast its spell without providing any material components. Otherwise, the scroll is unintelligible. Casting the spell by reading the scroll requires the spell''s normal casting time. Once the spell is cast, the words on the scroll fade, and it crumbles to dust. If the casting is uninterrupted, the scroll is not lost. If the spell is on your class''s spell list but of a higher level than you can normally cast, you must make an ability check using your spellcasting ability to determine whether you cast it successfully. The DC equals 10 + the spell''s level. On a failed check, the spell disappears from the scroll with no other effect.','{"requiresAttunement":false,"attunementClasses":[]}',false,true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name,rarity=EXCLUDED.rarity,description=EXCLUDED.description,properties=EXCLUDED.properties,requires_attunement=EXCLUDED.requires_attunement,is_magic=EXCLUDED.is_magic,updated_at=now();
